/**
 * 设置按钮状态
 * @param {text} button 按钮id
 * @param {boolean} state 状态
 */
function setBtnStyle(button, state) {
    if (state) {
        $("#" + button).css({ 'pointer-events': 'auto' });
        $("#" + button + " span").css({ 'color': '#000' });
    } else {
        $("#" + button).css({ 'pointer-events': 'none' });
        $("#" + button + " span").css({ 'color': 'grey' });
    }
}

